570	function buildWeeklyConfig(state: PlanEditorState): string | null {
571	  if (state.scheduleMode !== "weekly_fixed") return null;
572	
573	  const config: Record<string, string> = {};
574	  Object.entries(state.weeklyDayMap).forEach(([day, type]) => {
575	    if (type !== null) {
576	      // We use a placeholder — the actual biz_key will be set after save
577	      config[day] = type;
