48	  /** Number of completed exercises */
49	  completedExercises: number;
50	  /** Total number of exercises */
51	  totalExercises: number;
52	  /** Callback to record a set */
53	  onRecordSet: (
54	    exerciseBizKey: bigint,
55	    setData: {
56	      setIndex: number;
57	      targetWeight: number | null;
58	      targetReps: number;
59	      actualWeight: number | null;
60	      actualReps: number | null;
61	    },
62	  ) => void;
63	  /** Callback to complete an exercise */
64	  onCompleteExercise: (exerciseBizKey: bigint) => void;
65	  /** Callback to exit workout */
