99	function ExerciseItem({
100	  exercise,
101	  allExercises,
102	  sets,
103	  currentExerciseBizKey,
104	  exerciseName,
105	  increment,
106	  onRecordSet,
107	  onSkip,
108	  onDragStart,
109	  onDragEnd,
110	}: ExerciseItemProps) {
111	  const [showSkip, setShowSkip] = useState(false);
112	
113	  const handleLongPress = useCallback(() => {
114	    if (onDragStart) {
115	      onDragStart();
116	      // Auto-end drag after a short time (placeholder for full drag implementation)
117	      setTimeout(() => {
118	        onDragEnd?.();
119	      }, 1000);
120	    }
121	    // Toggle skip button visibility as part of interaction
122	    setShowSkip((prev) => !prev);
123	  }, [onDragStart, onDragEnd]);
124	
125	  return (
126	    <View style={exerciseItemStyles.container}>
