185	export function WorkoutScreen({
186	  trainingTypeLabel,
187	  exercises: initialExercises,
188	  setsByExercise,
189	  currentExerciseBizKey,
190	  exerciseNames,
191	  exerciseIncrements,
192	  completedExercises,
193	  totalExercises,
194	  onRecordSet,
195	  onCompleteExercise: _onCompleteExercise,
196	  onExit,
197	  onAllCompleted,
198	  onSelectExercise: _onSelectExercise,
199	  onReorderExercises: _onReorderExercises,
200	  onSkipExercise,
201	}: WorkoutScreenProps) {
202	  // Local state for drag reorder
203	  const [exercises, setExercises] = useState(initialExercises);
204	  const [_dragIndex, setDragIndex] = useState<number | null>(null);
205	
206	  // Sync with external state changes
207	  React.useEffect(() => {
208	    setExercises(initialExercises);
209	  }, [initialExercises]);
210	
211	  // Check if all exercises completed - trigger navigation
212	  const allDone = isAllExercisesCompleted(exercises);
213	
214	  // Use a ref to avoid repeated navigation
215	  const hasNavigated = React.useRef(false);
216	
217	  React.useEffect(() => {
218	    if (allDone && !hasNavigated.current) {
219	      hasNavigated.current = true;
220	      onAllCompleted();
221	    }
222	  }, [allDone, onAllCompleted]);
223	
224	  const handleRecordSet = useCallback(
225	    (exerciseBizKey: bigint) =>
226	      (setData: {
227	        setIndex: number;
228	        targetWeight: number | null;
229	        targetReps: number;
230	        actualWeight: number | null;
231	        actualReps: number | null;
232	      }) => {
233	        onRecordSet(exerciseBizKey, setData);
234	      },
235	    [onRecordSet],
236	  );
237	
238	  const handleDragStart = useCallback((index: number) => {
239	    setDragIndex(index);
240	  }, []);
241	
242	  const handleDragEnd = useCallback(() => {
243	    setDragIndex(null);
244	  }, []);
245	
246	  const handleSkip = useCallback(
247	    (exerciseBizKey: bigint) => {
248	      if (onSkipExercise) {
249	        onSkipExercise(exerciseBizKey);
250	      }
251	    },
252	    [onSkipExercise],
253	  );
254	
255	  return (
256	    <View style={styles.container}>
257	      <WorkoutHeader
258	        trainingTypeLabel={trainingTypeLabel}
259	        completedExercises={completedExercises}
260	        totalExercises={totalExercises}
261	        onExit={onExit}
262	      />
263	      <ScrollView
264	        style={styles.scrollView}
265	        contentContainerStyle={styles.scrollContent}
266	        testID="exercise-list"
267	      >
268	        {exercises.map((exercise, index) => {
269	          const exerciseName =
270	            exerciseNames.get(exercise.exercise_biz_key) ?? "Unknown";
271	          const increment =
272	            exerciseIncrements.get(exercise.exercise_biz_key) ?? 2.5;
273	          const sets = setsByExercise.get(exercise.biz_key) ?? [];
274	
275	          return (
276	            <ExerciseItem
277	              key={exercise.biz_key.toString()}
278	              exercise={exercise}
279	              allExercises={exercises}
280	              sets={sets}
281	              currentExerciseBizKey={currentExerciseBizKey}
282	              exerciseName={exerciseName}
283	              increment={increment}
284	              onRecordSet={handleRecordSet(exercise.exercise_biz_key)}
285	              onSkip={() => handleSkip(exercise.exercise_biz_key)}
286	              onDragStart={() => handleDragStart(index)}
287	              onDragEnd={handleDragEnd}
288	            />
289	          );
290	        })}
291	      </ScrollView>
292	    </View>
293	  );
294	}
