1	/**
2	 * ExerciseCard component for the workout execution page.
3	 *
4	 * Three visual states:
5	 * - Active (expanded): weight/reps input, "完成本组" button
6	 * - Completed (collapsed): ✓ checkmark, actual weight×reps summary
7	 * - Pending (muted grey): "待进行" label
8	 *
9	 * Supports same exercise distinction (e.g. "深蹲 #1", "深蹲 #2 - 暂停深蹲").
10	 */
11	
12	import React, { useState, useCallback } from "react";
13	import {
14	  View,
15	  Text,
16	  TouchableOpacity,
17	  StyleSheet,
18	  type ViewStyle,
19	} from "react-native";
20	import { Colors, Typography, Spacing } from "@utils/constants";
21	import type { WorkoutExercise, WorkoutSet } from "../../types";
22	import {
23	  getExerciseDisplayName,
24	  getWeightLabelType,
25	  formatWeightWithIncrement,
26	  formatSetProgress,
27	  formatSetSummary,
28	  getCompletedSetCount,
29	  getNextSetIndex,
30	  getExerciseCardState,
31	} from "./workout-helpers";
32	
33	export interface ExerciseCardProps {
34	  /** The workout exercise data */
35	  exercise: WorkoutExercise;
36	  /** All exercises in the workout (for duplicate detection) */
37	  allExercises: WorkoutExercise[];
38	  /** Completed sets for this exercise */
39	  sets: WorkoutSet[];
40	  /** Currently active exercise biz_key */
41	  currentExerciseBizKey: bigint | null;
42	  /** Exercise name from library */
43	  exerciseName: string;
44	  /** Increment value from exercise library */
45	  increment: number;
46	  /** Callback when "完成本组" is pressed */
47	  onRecordSet: (setData: {
48	    setIndex: number;
49	    targetWeight: number | null;
50	    targetReps: number;
51	    actualWeight: number | null;
52	    actualReps: number | null;
53	  }) => void;
54	  /** Callback when "加一组" is pressed */
55	  onAddExtraSet?: () => void;
56	  /** Optional style override */
57	  style?: ViewStyle;
58	}
59	
60	export function ExerciseCard({
61	  exercise,
62	  allExercises,
63	  sets,
64	  currentExerciseBizKey,
65	  exerciseName,
66	  increment,
67	  onRecordSet,
68	  onAddExtraSet,
69	  style,
70	}: ExerciseCardProps) {
71	  const cardState = getExerciseCardState(exercise, currentExerciseBizKey);
72	  const displayName = getExerciseDisplayName(
73	    exercise.biz_key,
74	    exerciseName,
75	    allExercises,
76	  );
77	
78	  if (cardState === "completed") {
79	    return (
80	      <CompletedCard
81	        displayName={displayName}
82	        sets={sets}
83	        style={style}
84	        exerciseBizKey={exercise.exercise_biz_key.toString()}
85	      />
86	    );
87	  }
88	
89	  if (cardState === "active") {
90	    return (
91	      <ActiveCard
92	        exercise={exercise}
93	        displayName={displayName}
94	        sets={sets}
95	        increment={increment}
96	        onRecordSet={onRecordSet}
97	        onAddExtraSet={onAddExtraSet}
98	        style={style}
99	      />
100	    );
101	  }
102	
103	  return <PendingCard displayName={displayName} style={style} />;
104	}
105	
106	// --- Completed (collapsed) Card ---
107	
108	interface CompletedCardProps {
109	  displayName: string;
110	  sets: WorkoutSet[];
111	  style?: ViewStyle;
112	  exerciseBizKey?: string;
113	}
114	
115	function CompletedCard({
116	  displayName,
117	  sets,
118	  style,
