120	}: CompletedCardProps) {
121	  const summary = formatSetSummary(sets);
122	
123	  return (
124	    <View
125	      style={[styles.card, styles.completedCard, style]}
126	      testID={exerciseBizKey ? `exercise-card-${exerciseBizKey}` : undefined}
127	    >
