136	
137	// --- Active (expanded) Card ---
138	
139	interface ActiveCardProps {
140	  exercise: WorkoutExercise;
141	  displayName: string;
142	  sets: WorkoutSet[];
143	  increment: number;
144	  onRecordSet: (setData: {
145	    setIndex: number;
146	    targetWeight: number | null;
147	    targetReps: number;
148	    actualWeight: number | null;
149	    actualReps: number | null;
150	  }) => void;
151	  onAddExtraSet?: () => void;
152	  style?: ViewStyle;
153	}
154	
155	function ActiveCard({
156	  exercise,
157	  displayName,
158	  sets,
159	  increment,
160	  onRecordSet,
161	  onAddExtraSet,
162	  style,
163	}: ActiveCardProps) {
164	  const completedCount = getCompletedSetCount(sets);
165	  const nextSetIndex = getNextSetIndex(sets);
166	
167	  // Determine initial weight (suggested or from last set)
168	  const lastCompletedSet = [...sets]
169	    .reverse()
170	    .find((s) => s.is_completed === 1);
171	  const suggestedWeight = exercise.suggested_weight;
172	  const initialWeight =
173	    lastCompletedSet?.actual_weight ?? suggestedWeight ?? null;
174	
175	  const [weightInput, setWeightInput] = useState<string>(
176	    initialWeight !== null ? String(initialWeight) : "",
177	  );
178	  // setRepsInput will be used when reps editing is wired up
179	  const [repsInput, _setRepsInput] = useState<string>(
180	    String(exercise.target_reps),
181	  );
182	
183	  const weightLabelType = getWeightLabelType(
184	    suggestedWeight,
185	    weightInput !== "" ? Number(weightInput) : null,
186	  );
187	
188	  const handleCompleteSet = useCallback(() => {
189	    const actualWeight = weightInput !== "" ? Number(weightInput) : null;
190	    const actualReps = repsInput !== "" ? Number(repsInput) : null;
191	
192	    onRecordSet({
193	      setIndex: nextSetIndex,
194	      targetWeight: suggestedWeight,
195	      targetReps: exercise.target_reps,
196	      actualWeight,
197	      actualReps,
198	    });
199	
200	    // Pre-fill for next set with same weight
201	    if (actualWeight !== null) {
202	      setWeightInput(String(actualWeight));
203	    }
204	  }, [
205	    weightInput,
206	    repsInput,
207	    nextSetIndex,
208	    suggestedWeight,
209	    exercise.target_reps,
210	    onRecordSet,
211	  ]);
212	
213	  const setProgressText = formatSetProgress(
214	    completedCount,
215	    exercise.target_sets,
216	  );
217	
218	  return (
219	    <View
220	      style={[styles.card, styles.activeCard, style]}
221	      testID={`exercise-card-${exercise.exercise_biz_key.toString()}`}
222	    >
223	      {/* Header: name + set progress */}
224	      <View style={styles.activeHeader}>
225	        <Text style={styles.activeName}>{displayName}</Text>
226	        <Text style={styles.setProgress}>{setProgressText}</Text>
227	      </View>
228	
229	      {/* Suggestion label */}
230	      {suggestedWeight !== null && (
231	        <View style={styles.suggestionRow}>
232	          {weightLabelType === "suggested" ? (
233	            <Text style={styles.suggestionText} testID="suggested-weight">
234	              建议: {formatWeightWithIncrement(suggestedWeight, increment)}
235	            </Text>
236	          ) : weightLabelType === "custom" ? (
237	            <Text style={styles.customLabel} testID="custom-weight-badge">
238	              自定义
239	            </Text>
240	          ) : null}
241	        </View>
242	      )}
243	
244	      {/* Weight + Reps inputs */}
245	      <View style={styles.inputRow}>
246	        <View style={styles.weightInputContainer}>
247	          <Text style={styles.weightDisplay} testID="suggested-weight">
248	            {weightInput || "0"}
249	          </Text>
250	          <Text style={styles.inputUnit}> kg</Text>
251	        </View>
252	        <View style={styles.repsInputContainer}>
253	          <Text style={styles.repsDisplay} testID="reps-input">
254	            {repsInput}
255	          </Text>
256	          <Text style={styles.inputUnit}> 次</Text>
257	        </View>
258	      </View>
259	
260	      {/* Target sets/reps display */}
261	      <View style={styles.targetRow}>
262	        <Text style={styles.targetText} testID="target-sets-reps">
263	          目标: {exercise.target_sets}组 x {exercise.target_reps}次
264	        </Text>
265	      </View>
266	
267	      {/* Complete set button */}
268	      <TouchableOpacity
269	        style={styles.completeButton}
270	        onPress={handleCompleteSet}
271	        accessibilityRole="button"
272	        accessibilityLabel="完成本组"
273	        testID="complete-set-btn"
274	      >
275	        <Text style={styles.completeButtonText}>完成本组</Text>
276	      </TouchableOpacity>
277	
278	      {/* Add extra set (when all planned sets done) */}
